export const UNIFESP_2026_QUESTIONS: any[] = [
  { id: "unifesp_2026_001", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Anestesiologia", text: "Mulher, 72 anos de idade, ex-tabagista (40 anos/maço), diagnosticada com DPOC GOLD II (VEF1 55%), controlada com tiotrópio inalatório diário e salbutamol, submeter-se-á à artroplastia total de quadril eletiva por osteoartrose avançada. Não apresenta exacerbações nos últimos 6 meses ou hospitalizações prévias por insuficiência respiratória. Apresenta saturação de O2 de 93% em ar ambiente. Radiografia de tórax: normal. ECG: ritmo sinusal. Qual é a conduta mais adequada?", options: ["Prosseguir com a cirurgia eletiva, preferencialmente com anestesia regional, mantendo otimização broncodilatadora e fisioterapia respiratória no perioperatório", "Postergar a cirurgia e iniciar corticoide sistêmico profilático por 7 dias com espirometria prévia e nova avaliação funcional pulmonar.", "Prosseguir com a cirurgia, sem exames adicionais, priorizando anestesia geral com intubação e ventilação mecânica, e broncodilatadores de rotina.", "Solicitar tomografia de alta resolução de tórax e gasometria arterial, além de avaliação com pneumologista antes da liberação cirúrgica."], correctIndex: 0 },
  { id: "unifesp_2026_002", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia Pediátrica", text: "Menino, 2 meses de idade, nascido a termo, 3.750 g, Apgar 9/10, é trazido pela mãe que refere demora na cicatrização do coto umbilical, que caiu com um mês de vida. Apresenta saída recorrente de secreção achocolatada aerada pelo umbigo. Qual é o diagnóstico mais provável?", options: ["Persistência de úraco", "Onfalite", "Persistência de conduto onfalomesentérico", "Granuloma piogênico umbilical"], correctIndex: 2 },
  { id: "unifesp_2026_003", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia Pediátrica", text: "Menino, um ano de idade, apresenta dor abdominal em cólica, vômitos e distensão abdominal há 8 horas. Exame físico: abdômen distendido, sem sinais de irritação peritoneal e ruídos hidroaéreos aumentados. Toque retal: presença de sangue na ampola retal, sem qualquer outra alteração. Qual é o exame complementar mais adequado?", options: ["RX contrastado de abdome", "Tomografia de abdome", "Colonoscopia", "Ultrassonografia de abdome"], correctIndex: 3 },
  { id: "unifesp_2026_004", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Dermatologia", text: "Homem, 68 anos de idade, agricultor, com exposição solar crônica, queixa-se de lesão ulcerada e crostosa no nariz há 8 meses, com crescimento progressivo e sangramento esporádico. Exame físico: lesão de 1,5 cm, com ulceração central, bordas elevadas e peroladas na asa nasal direita. Não há linfonodos palpáveis na região cervical. Além da fotoproteção, qual é a conduta mais adequada?", options: ["Corticoterapia e reavaliação em 3 meses.", "Biópsia incisional.", "Biópsia por shaving.", "Biópsia excisional com margem de 0,5 cm."], correctIndex: 3 },
  { id: "unifesp_2026_005", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia Torácica", text: "Homem, 23 anos de idade, apresentou primeiro episódio de pneumotórax espontâneo à direita e foi submetido à drenagem pleural. Após expansão e resolução do pneumotórax recebeu alta com orientação para seguimento ambulatorial. Um ano depois apresentou quadro de pneumotórax espontâneo, agora à esquerda, primeiro episódio. Qual é a conduta mais adequada?", options: ["Aguardar 2º episódio para indicar cirurgia.", "Indicar bulectomia e pleurodese bilateral.", "Drenagem pleural à esquerda e pleurodese à esquerda.", "Drenagem pleural à esquerda e pleurodese à direita."], correctIndex: 1 },
  { id: "unifesp_2026_006", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia Torácica", text: "Homem, 67 anos de idade, com antecedente de 90 anos-maço, tem lesão espiculada em LSE de 4 cm de diâmetro. A biópsia da lesão revelou tratar-se de carcinoma espinocelular primário de pulmão. A tomografia de tórax mostrou linfonodomegalia mediastinal ipsilateral em cadeia 4. O PET Scan revelou aumento de SUV em lesão descrita acima, porém sem outros locais de captação. A ultrassonografia endobrônquica para biópsia dos linfonodos mediastinais foi negativa. Qual é a conduta mais adequada?", options: ["Lobectomia superior esquerda", "Realizar a mediastinoscopia", "Quimioterapia neoadjuvante", "Radioterapia conformacional"], correctIndex: 1 },
  { id: "unifesp_2026_007", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Oftalmologia", text: "Adolescente, 15 anos de idade, sofreu trauma na região orbitária durante uma partida de tênis que evoluiu com equimose e imobilidade quase completa do globo ocular. Exame físico: enoftalmia e rebordo orbitário íntegro à palpação. Qual é o diagnóstico mais provável?", options: ["Fratura isolada da maxila", "Fratura isolada do arco zigomático", "Fratura isolada do osso frontal", "Fratura isolada da órbita interna"], correctIndex: 3 },
  { id: "unifesp_2026_008", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "Homem, 20 anos de idade, chega ao pronto socorro vítima de acidente automobilístico. A radiografia de tórax mostra fratura de primeiros arcos costais à esquerda, alargamento mediastinal e rebaixamento de brônquio principal esquerdo. Qual é o diagnóstico mais provável?", options: ["Lesão de aorta", "Lesão de esôfago", "Lesão cardíaca", "Lesão de hilo pulmonar"], correctIndex: 0 },
  { id: "unifesp_2026_009", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia Vascular", text: "Homem, 65 anos de idade, tabagista, relata dor em panturrilhas após caminhar por 100 metros, aliviada com o repouso. O índice tornozelo-braquial é de 0,6 no membro inferior direito. Não há sinais de infecção ou necrose. Qual é a conduta inicial mais adequada?", options: ["Tratamento clínico", "Revascularização endovascular", "Amputação primária", "Revascularização convencional"], correctIndex: 0 },
  { id: "unifesp_2026_010", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia Vascular", text: "Homem, 30 anos de idade, em uso de anticoagulante por arritmia, foi vítima de ferimento por arma branca na face medial da coxa direita há 2 horas. Apresenta sangramento ativo, ausência de pulso distal e extremidade fria no membro. Qual é a conduta mais adequada?", options: ["Angiotomografia com contraste endovenoso.", "Compressão manual e encaminhamento ao centro cirúrgico.", "Reposição de fatores vitamina K dependente e observar evolução.", "Arteriografia com subtração digital."], correctIndex: 1 },
  { id: "unifesp_2026_011", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "Mulher, 27 anos de idade, sem comorbidades, apresenta dor abdominal difusa que migra para fossa ilíaca direita há 24h. Exame físico: dor localizada em abdome inferior com defesa. Laboratório: leucocitose e PCR elevada. Tomografia de abdômen: inconclusiva. Qual é a conduta mais adequada?", options: ["Ressonância nuclear magnética de pelve com gadolíneo.", "Antibioticoterapia empírica intravenosa e reavaliação clínica em 12h.", "Observação ambulatorial com novo exame de imagem em 24h.", "Videolaparoscopia diagnóstica, com apendicectomia se não encontrar nenhuma outra doença."], correctIndex: 3 },
  { id: "unifesp_2026_012", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Urologia", text: "Homem, 75 anos de idade, em tratamento de câncer de próstata metastático, em uso de tansulosina, leuprorrelina e enzalutamida, não apresenta evidência de progressão de doença nos últimos 18 meses. Relata piora dos sintomas urinários obstrutivos há 6 meses. Nega antecedentes cirúrgicos. Exames: PSA 1,4ng/dL, Ureia 80 mg/dL e Creatinina 1,8 mg/dL. Ultrassonografia de abdômen: volume prostático de 30 g e resíduo pós-miccional de 330 mL. Qual é a conduta mais adequada?", options: ["Prostatectomia Radical", "Radioterapia Externa", "RTU de próstata", "Braquiterapia"], correctIndex: 2 },
  { id: "unifesp_2026_013", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "Homem, 55 anos de idade, portador de hemorroidas grau IV, com histórico familiar de pólipos adenomatosos colônicos em avô materno, apresenta alteração de hábito intestinal nos últimos 6 meses, com episódios frequentes de diarreia e sangramento por via retal. É portador de bloqueio atrioventricular completo e utiliza marcapasso há 3 anos. Qual é a conduta mais adequada?", options: ["Hemorroidectomia a Milligan-Morgan", "Colonoscopia", "Ligadura elástica", "Pesquisa de sangue oculto nas fezes"], correctIndex: 1 },
  { id: "unifesp_2026_014", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Urologia", text: "Homem, 30 anos de idade, apresenta cálculo de 2 cm no polo inferior do rim esquerdo. Qual é a conduta mais adequada?", options: ["Nefrolitotripsia percutânea", "Litotripsia extracorporea", "Nefrolitotripsia transureteroscópica flexivel", "Alcalinização da urina"], correctIndex: 0 },
  { id: "unifesp_2026_015", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "Homem, 56 anos de idade, procura o pronto-socorro com dor súbita e aumento do volume na região inguinal direita há 6 horas. Exame físico: abaulamento doloroso da região inguinal, sem sinais de peritonite. Durante o exame físico, a hérnia reduziu espontaneamente. Qual é a conduta mais adequada?", options: ["Hernioplastia aberta.", "Hernioplastia laparoscópica.", "Observação clínica por 24 horas.", "Laparotomia exploradora."], correctIndex: 1 },
  { id: "unifesp_2026_016", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "Mulher, 75 anos de idade, apresenta dor torácica e epigástrica aguda há 3 horas, acompanhada de vômitos. Refere histórico de hérnia de hiato. Exame físico: REG, FC 110 bpm, PA 80 x 40 mm Hg, FR 33 irpm, T 37 °C, com fácies de dor. Eletrocardiograma: normal. Radiografia de tórax com massa e nível hidroaéreo no mediastino posterior e inferior. Qual é a conduta mais adequada após estabilização clínica inicial?", options: ["Ecocardiograma transtorácico", "Endoscopia digestiva alta", "Broncoscopia", "Ultrassonografia FAST"], correctIndex: 1 },
  { id: "unifesp_2026_017", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia", text: "Homem, 56 anos de idade, apresenta adenocarcinoma retal a 7 cm da borda anal, de aproximadamente 3 cm de extensão, sem evidência de comprometimento linfonodal ou metástases à distância ao estadiamento. Qual é a conduta mais adequada?", options: ["Amputação abdominoperineal.", "Neoadjuvância com quimioterapia.", "Neoadjuvância com radioterapia.", "Retossigmoidectomia com excisão do mesorreto."], correctIndex: 3 },
  { id: "unifesp_2026_018", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cirurgia Vascular", text: "Homem, 32 anos de idade, portador de Síndrome de Marfan, procura o PS com dor no dorso de forte intensidade, incaracterística, com irradiação para abdômen, associada a sudorese, há 2 horas. Exame físico: consciente, GCS 15, PA 180 x 100 mmHg, FC 120 bpm, BRNF em 2T sem sopros, MV presente com macicez à percussão no terço inferior do hemitórax esquerdo, abdômen doloroso à palpação superficial, DB negativo, RHA presentes e diminuídos, sem sinais de isquemia mesentérica ou alterações de pulsos nos membros inferiores. Após avaliação da angiotomografia, qual é a conduta mais adequada?", options: ["Tratamento endovascular", "Cirurgia de emergência", "Tratamento clínico", "Drenagem pleural"], correctIndex: 0 },
  { id: "unifesp_2026_019", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ortopedia", text: "Homem, 22 anos de idade, vítima de colisão moto e auto, trazido pelo Corpo de Bombeiros ao Pronto Atendimento, apresentando trauma cranioencefálico, hemopneumotórax à D e deformidade em membro inferior direito e membro superior direito. Radiografias: fraturas fechadas da diáfise do fêmur D, do planalto tibial D, fratura-luxação bimaleolar do tornozelo D e do úmero distal D. Após estabilização clínica inicial na sala de emergência, qual é a conduta ortopédica mais adequada?", options: ["Imobilização gessada e aguardar melhora clínica do paciente.", "Redução e fixação interna das fraturas com hastes, placas e parafusos.", "Fixação definitiva das fraturas e deformidades com método Ilizarov.", "Redução e estabilização das fraturas com fixadores externos transarticulares."], correctIndex: 3 },
  { id: "unifesp_2026_020", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ortopedia", text: "Mulher, 78 anos de idade, é trazida ao PS com história de queda da própria altura, evoluindo com dor no quadril D e consequente incapacidade a deambulação. Antecedentes pessoais: dependente de cuidadores em casa de repouso, arritmia, demência e diabetes tipo II sem controle. Radiografias: fratura desviada instável do colo do fêmur D, sem osteoartrose. Qual é a conduta mais adequada?", options: ["Redução e fixação percutânea com parafusos canulados.", "Artroplastia total do quadril.", "Artroplastia parcial do quadril.", "Redução e fixação com haste cefalomedular."], correctIndex: 2 },
  { id: "unifesp_2026_021", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ortopedia", text: "Homem, 40 anos de idade, com queixa de dor no ombro D após queda ao solo sem desnível. Exame físico sem alterações, exceto por dor e perda de força a rotação lateral do ombro D. Radiografias sem alterações. Qual é o diagnóstico mais provável?", options: ["Lesão do tendão do subescapular.", "Lesão do tendão do peitoral maior.", "Lesão do tendão do infraespinhal.", "Lesão do tendão da cabeça longa do bíceps braquial."], correctIndex: 2 },
  { id: "unifesp_2026_022", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Clínica Médica", text: "Homem, 48 anos de idade, morador de área livre, foi internado com quadro de uma semana de confusão mental e diarreia, evacuando fezes aquosas várias vezes ao dia com urgência. Ele estava confuso e desorientado em relação ao espaço e ao tempo. Relata ingerir aproximadamente 100 mL de destilado por dia. Exame físico: alerta, confuso, exame neurológico normal e sem nistagmo ou oftalmoplegia; dentes em mau estado de conservação; erupção cutânea eritematosa, simétrica e sem coceira, predominantemente na face, pescoço, mãos e antebraços, com algumas bolhas. Qual é a deficiência nutricional mais provável?", options: ["Cioanocobalamina (B12)", "Piridoxina (B6)", "Niacina (B3)", "Tiamina (B1)"], correctIndex: 2 },
  { id: "unifesp_2026_023", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Homem, 62 anos de idade, apresenta dispneia progressiva aos moderados esforços e ortopneia há 6 meses. Exame fisico: turgência jugular patológica; murmúrio vesicular presente bilateralmente com estertores crepitantes em ambas as bases; bulhas cardíacas rítmicas com presença de terceira bulha, ictus palpável no sexto espaço intercostal esquerdo na linha axilar anterior, onde se ausculta um sopro sistólico regurgitativo 3+/6+ irradiado para axila, e edema simétrico de membros inferiores 2+/4+. Qual é a causa mais provável do sopro?", options: ["Insuficiência aórtica primária", "Prolapso de valva mitral", "Insuficiência mitral funcional", "Abscesso de valva mitral esquerda"], correctIndex: 2 },
  { id: "unifesp_2026_024", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Homem, 55 anos de idade, previamente saudável, chega ao serviço de emergência 60 min após início de dor torácica anginosa típica. Eletrocardiograma: supra de ST em parede anterior. Exame físico: PA = 70/45 mmHg, FC = 110 bpm, extremidades frias, tempo de enchimento capilar = 6 segundos. Enquanto se organiza a transferência imediata para angioplastia primária, qual é a droga vasoativa mais adequada para restabelecer a pressão arterial e a perfusão tecidual neste cenário?", options: ["Noradrenalina", "Dobutamina", "Dopamina", "Vasopressina"], correctIndex: 0 },
  { id: "unifesp_2026_025", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Homem, 20 anos de idade, em acompanhamento por transtorno bipolar, é avaliado em consulta devido a queixa de aumento da sede e da diurese. Exames laboratoriais séricos pertinentes: cálcio total = 15,1 mg/dL (VR 8,2-10,6 mg/dL), fósforo = 3,4 mg/dL (VR 2,5-4,5 mg/dL), creatinina = 0,95 mg/dL (VR 0,70-1,10 mg/dL), PTH = 10 pg/mL (VR 10-70 pg/mL). Qual é a hipótese diagnóstica mais provável?", options: ["Carcinoma de paratiroide", "Uso de lítio", "Mutação inativadora do sensor de cálcio", "Intoxicação por vitamina D"], correctIndex: 3 },
  { id: "unifesp_2026_026", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Mulher, 30 anos de idade, é atendida no PS por apresentar, agudamente, dificuldade para andar e referindo visão dupla. A irmã acha que ela está confusa e desorientada. Exame físico: paciente emagrecida, com excesso de pele, desorientada no tempo e espaço, confusa, com nistagmo multidirecional, alteração do equilíbrio, dificuldade para ficar em pé e caminhar. Antecedentes pessoais: hipertensão arterial, obesidade tratada com cirurgia bariátrica há 3 anos. Qual é o diagnóstico mais provável?", options: ["Encefalite Viral por Herpes Vírus tipo 1", "Encefalopatia por deficiência de vitamina A", "Encefalopatia de Wernicke", "Encefalite autoimune por anticorpos anti-NMDAR"], correctIndex: 2 },
  { id: "unifesp_2026_027", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Intensiva", text: "Homem, 60 anos de idade, é transferido do PS para a unidade de terapia intensiva com insuficiência respiratória hipoxêmica, presumivelmente secundária a sepse de foco pulmonar. Exame físico inicial: Escala de Coma de Glasgow = 14, FC = 120 bpm, PA = 130/80 mmHg, FR = 25 irpm, SpO₂ = 88 % em máscara facial com reservatório. Diante desse quadro, decide-se pela intubação orotraqueal e início de ventilação mecânica invasiva. Qual é o ajuste inicial mais adequado do ventilador para esse paciente?", options: ["Modo ventilatório controlado a volume, volume corrente inicial de 6mL/kg de peso predito para altura, FiO2 de 100%, frequência respiratória de 20 irpm, PEEP de 8 cm H2O.", "Modo ventilatório controlado a volume, volume corrente inicial de 8 mL/kg de peso real, FiO2 de 50%, frequência respiratória de 10 irpm, PEEP de 5 cm H2O.", "Modo ventilatório controlado a volume, volume corrente inicial de 10 mL/kg de peso predito para altura, FiO2 de 50%, frequência respiratória de 20 irpm, PEEP de 8cm H2O.", "Modo ventilatório controlado a volume, volume corrente inicial de 6 mL/kg de peso real, FiO2 de 100%, frequência respiratória de 10 irpm, PEEP de 5 cm H2O."], correctIndex: 0 },
  { id: "unifesp_2026_028", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Mulher, 82 anos de idade, é admitida no pronto-atendimento por piora da dispneia, ortopneia, cefaleia e náuseas há 12 horas. Antecedentes pessoais: insuficiência cardíaca com fração de ejeção de 58%, hipertensão arterial sistêmica, diabetes mellitus e fibrilação atrial paroxística. Exame físico: PA= 180/120 mmHg em ambos os membros superiores, FC = 155 bpm, FR = 35 irpm, SpO2 = 85% em ar ambiente, tempo de enchimento capilar de 4 segundos, bulhas cardíacas arrítmicas sem sopros, ausculta pulmonar com estertores crepitantes em campos médio-inferiores bilateralmente. ECG: ritmo de fibrilação atrial e presença de strain lateral de ventrículo esquerdo. Qual é a estratégia terapêutica inicial mais adequada?", options: ["Ventilação invasiva, dobutamina endovenosa e furosemida endovenosa.", "Ventilação não invasiva, dobutamina endovenosa e captopril via oral.", "Ventilação invasiva, metoprolol endovenoso e furosemida endovenosa.", "Ventilação não invasiva, nitrato endovenoso e furosemida endovenosa."], correctIndex: 3 },
  { id: "unifesp_2026_029", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Nefrologia", text: "Homem, 74 anos de idade, com DRC estágio 5 não dialítico (TFG estimada = 9 mL/min/1,73m²), apresenta-se no PS com sonolência progressiva, náuseas, fraqueza muscular e episódios de vômitos nos últimos dois dias. Faz uso regular de um suplemento de magnésio (500 mg/dia) prescrito para cãibras. Exame físico: PA = 95/60 mmHg, FC = 48 bpm; ausculta cardíaca sem sopros; reflexos profundos diminuídos. ECG: intervalo PR prolongado e QRS discretamente alargado. Exame laboratorial: magnésio sérico = 8,6 mg/dL (VR 1,7-2,2 mg/dL). Além da suspensão do suplemento, qual é a conduta mais adequada neste momento?", options: ["Infusão de gluconato de cálcio intravenoso e início de hemodiálise", "Administração de solução salina isotônica e furosemida intravenosa", "Administração de sorbitol associado a resina de troca iônica", "Infusão de bicarbonato de sódio e início de hemodiálise"], correctIndex: 0 },
  { id: "unifesp_2026_030", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Mulher, 48 anos de idade, queixa-se de perda de peso de 10 kg em 3 meses. Refere que há 4 meses vem apresentando calor, sudorese, tremor de extremidades e palpitações. Há 2 meses, percebeu o pescoço mais inchado e, há 1 mês, que os olhos estão vermelhos, o que atribuiu ao uso de um novo creme cosmético. Qual é o diagnóstico mais provável?", options: ["Hipertiroidismo por tiroidite subaguda.", "Hipertiroidismo de origem autoimune.", "Hipertiroidismo por tumor produtor de TSH.", "Doença ocular da tiroide secundária ao estímulo de TSH."], correctIndex: 1 },
  { id: "unifesp_2026_031", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Dermatologia", text: "Mulher, 67 anos de idade, pele fototipo I, comparece ao ambulatório para avaliação de lesões cutâneas na face. Faz uso de paracetamol, hidroclorotiazida, metoprolol, sinvastatina, insulina e um multivitamínico. Exame físico: eritema na face, colo e braços, associado a várias pápulas eritematosas de superfície áspera e descamativa. Considerando o diagnóstico mais provável, qual dos seguintes medicamentos deve ser substituído?", options: ["Paracetamol", "Hidroclorotiazida", "Metoprolol", "Sinvastatina"], correctIndex: 1 },
  { id: "unifesp_2026_032", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Geriatria", text: "Mulher, 84 anos de idade, comparece ao ambulatório acompanhada da filha, que relata o retorno de episódios de agitação nos últimos 5 dias, principalmente no fim da tarde. A paciente não tem dormido bem e, em um dos episódios, levantou-se da cama e retirou as roupas. Apresenta histórico de cinco quedas nos últimos 45 dias, palidez labial episódica durante os momentos de agitação e recusa ocasional em aferir a pressão arterial. Há 1 mês, iniciou o uso de quetiapina e dipirona. Qual é a hipótese diagnóstica principal?", options: ["Reação adversa a antipsicótico.", "Descompensação de quadro demencial crônico.", "Delirium do tipo hiperativo.", "Transtorno do sono relacionado ao envelhecimento."], correctIndex: 2 },
  { id: "unifesp_2026_033", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Homem, 56 anos de idade, foi admitido há 10 dias por abdome agudo causado por colecistite complicada, com sinais de perfuração intestinal e peritonite na propedeutica admissional. Foi iniciado ceftriaxona e metronidazol e o paciente foi submetido a cirurgia com laparotomia exploradora e colecistectomia, com dreno de Penrose posicionado em hipocôndrio direito desde então. A drenagem de secreção reduziu-se desde a admissão, com última mensuração em 24 horas de 50-60 mL de conteúdo hemático escurecido. Há 1 dia, vem apresentando febre, taquicardia, calafrios e dor à manipulação do dreno. Foi realizada TC de abdome com contraste que evidenciou coleção subfrênica de conteúdo denso, heterogêneo e trabeculado. Foi submetido a drenagem por radiointervenção com retirada de 50 mL de líquido hemático denso, enviado para cultura. O resultado da cultura evidenciou Pseudomonas aeruginosa resistente a amicacina, cefepima, ceftazidima, ciprofloxacino, gentamicina, imipenem e levofloxacino, sensibilidade intermediária a meropenem e piperacilina-tazobactam. Qual é a alternativa correta?", options: ["Pela espécie envolvida e padrão fenotípico, trata-se de infecção domiciliar, não tendo relação com infecção relacionada à assistência à saúde.", "Pela espécie envolvida e padrão fenotípico, é possível afirmar que o agente isolado é produtor de beta-lactamase de espectro ampliado (ESBL).", "A hipótese atual é de infecção de sítio cirúrgico e tanto piperacilina-tazobactam como meropenem podem ser iniciados, devendo-se priorizar doses máximas e infusão prolongada.", "O antibiograma requer que seja iniciado tratamento com ceftazidima-avibactam, uma vez que o agente isolado é multirresistente."], correctIndex: 2 },
  { id: "unifesp_2026_034", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Nefrologia", text: "Homem, 68 anos de idade, com diagnóstico de diabetes mellitus do tipo 2 e hipertensão há 20 anos, compensado clinicamente, vem em consulta de rotina, sem queixas. Exame físico: PA = 128/82 mmHg, sem outras alterações. Exames laboratoriais: creatinina = 1,50 mg/dL (TFGe por CKD-EPI = 50 mL/min/1,73m²), ureia = 42 mg/dL, sódio = 138 mEq/L, potássio = 4,2 mEq/L, glicemia de jejum = 102 mg/dL, Hb1Ac = 6,2%; urina 1: pH = 5,5, densidade = 1015, proteína +, hematúria ausente, glicosúria ausente; relação albumina/creatinina em amostra isolada de urina = 400 mg/g. Faz uso de enalapril 40 mg/dia, anlodipino 10 mg/dia, metformina 2000 mg/dia. Foi iniciado dapaglifozina 10 mg/d. Após 4 semanas, o paciente retorna em consulta, assintomático, sem queixas ou intercorrências no período, trazendo novos exames: creatinina = 1,67 mg/dL (TFGe por CKD-EPI = 44 mL/min/1,73m²), ureia = 40 mg/dL, sódio = 138 mEq/L, potássio = 4,2 mEq/L. Qual é a conduta mais adequada?", options: ["Manter todas as medicações em uso atual e reavaliar em próxima consulta.", "Manter as medicações em uso prévio e suspender dapaglifozina.", "Suspender a metformina e manter a dapaflifozina.", "Suspender o enalapril e manter a dapaglifozina."], correctIndex: 0 },
  { id: "unifesp_2026_035", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Homem, 52 anos de idade, chega ao pronto socorro com história de dor e edema em tornozelo esquerdo há 1 semana, que o impossibilita de andar. Nega traumas ou febre. Fez uso de paracetamol e diclofenaco sódico por 3 dias sem melhora. Relata que já teve episódios de dor semelhante em háluxes nos 4 anos anteriores. Tem hipertensão arterial e dislipidemia, fazendo uso de losartana, hidroclorotiazida e sinvastatina. Considerando o diagnóstico mais provável, qual é a conduta mais adequada?", options: ["Introduzir oxacilina intravenosa e realizar lavagem articular.", "Iniciar alopurinol e suspender a sinvastatina.", "Iniciar opioide e betametasona intramuscular.", "Iniciar colchicina e suspender o uso de tiazídico."], correctIndex: 3 },
  { id: "unifesp_2026_036", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Mulher, 56 anos de idade, possui diagnóstico de artrite reumatoide há 10 anos, já tendo realizado diversos tipos de tratamento e, diante da refratariedade dos sintomas, irá iniciar uso de adalimumabe (anti-TNFα). Foi encaminhada para avaliação de profilaxia para tuberculose e não apresenta sintomas respiratórios. Radiografia de tórax normal. Qual é a conduta mais adequada neste caso?", options: ["Iniciar imediatamente tratamento preventivo para tuberculose com prescrição de 3HP.", "Liberar para o uso de adalimumabe, pois não é necessária a realização de tratamento preventivo para tuberculose.", "Solicitar tomografia de tórax para descartar tuberculose ativa.", "Solicitar realização de prova tuberculínica ou IGRA, para posterior avaliação de indicação de tratamento preventivo para tuberculose."], correctIndex: 3 },
  { id: "unifesp_2026_037", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Mulher, 67 anos de idade, apresenta dor e rigidez matinal maior que 1 hora nos ombros e quadris há três meses. Relata também perda ponderal de 3 kg e febre baixa não aferida. Em investigação diagnóstica, foram afastadas causas infecciosas e neoplasias. Além disso, os exames laboratoriais evidenciaram: anemia normocítica e normocrômica (Hb = 9,6 g/dL), provas inflamatórias elevadas (VHS = 75 mm/1ª hora e PCR = 63 mg/L), fator reumatoide e fator antinuclear negativos. A ultrassonografia de partes moles revelou bursite subacromial bilateral e tendinopatia e bursite glútea bilateral. Qual é o diagnóstico mais provável?", options: ["Osteoartrite de ombros e quadris", "Artrite reumatoide", "Artropatia microcristalina", "Polimialgia reumática"], correctIndex: 3 },
  { id: "unifesp_2026_038", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Homem, 42 anos de idade, agricultor, passava bem até dois meses atrás, quando apresentou perda súbita de consciência por crise convulsiva. Cerca de 15 dias depois, passou a apresentar tosse com expectoração amarelada, chegando a expelir mais de 100 mL de secreção em 24 horas. Neste período, passou a apresentar adinamia, perdeu o apetite e emagreceu 6 kg. Acha que tem tido febre diariamente. É tabagista há 25 anos (4 cigarros de palha/dia) e consome cerca de 200 mL/dia de destilado há 20 anos. Exame físico: regular estado geral, eupneico, descorado, anictérico, acianótico; IMC = 17 kg/m2, PA = 135/78 mmHg, FC = 92 bpm, FR = 18 irpm, SpO2 = 94%; dentes em mau estado de conservação; diminuição da expansibilidade na base do hemitórax D, com aumento do frêmito toracovocal, macicez à percussão e broncofonia aumentada neste local, além de roncos difusos. Exames laboratoriais: hemograma com Hb = 9,7 g/dL, Ht = 30%, leucócitos totais = 16.300/mm3 com desvio à esquerda, plaquetas = 500.000/mm3; VHS = 75 mm/h; PCR = 40 mg/dL. Qual é a principal hipótese diagnóstica e qual o exame de imagem mais adequado para a investigação?", options: ["Câncer de pulmão abscedado; tomografia de tórax de alta resolução.", "Tuberculose pulmonar; tomografia de tórax convencional.", "Abscesso pulmonar primário; radiografia de tórax em PA e perfil.", "Bronquiectasia infectada; radiografia de tórax em PA e perfil."], correctIndex: 2 },
  { id: "unifesp_2026_039", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Dermatologia", text: "Homem, 32 anos de idade, previamente hígido, sofreu acidente de motocicleta há cerca de 40 dias com trauma cranioencefálico. Atendido em PS, recebeu prescrição de carbamazepina, que vem utilizando desde então. Há cerca de uma semana, apresenta lesões no corpo todo e febre. Exame físico: febril, com exantema rubeoliforme, edema de face e palpebral e linfonodomegalia generalizada. Qual é o diagnóstico mais provável?", options: ["DRESS", "Síndrome de Stevens-Johnson", "Eritema polimorfo minor", "Necrólise epidérmica tóxica"], correctIndex: 0 },
  { id: "unifesp_2026_040", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Homem, 68 anos de idade, fumante atual (45 anos-maço), tem diagnóstico de DPOC. Começou a apresentar dispneia progressiva aos esforços, piora da tosse e aumento do volume de escarro. Iniciou uso de formoterol 12 mcg associado a budesonida 400 mcg a cada 12 horas via inalatória, sem melhora do quadro após 3 meses. Exame físico: corado e hidratado, FR = 14 irpm, SpO2 92% em repouso; ausculta pulmonar com sons pulmonares reduzidos e sem ruídos adventícios; sem outras alterações. Espirometria com padrão obstrutivo não totalmente reversível. Qual é a conduta farmacológica mais adequada? (LABA = agonistas beta2-adrenérgicos de longa duração; LAMA = broncodilatadores antagonistas muscarínicos de longa duração)", options: ["Trocar os medicamentos inalatórios para uma associação LAMA/LABA e associar salbutamol de alívio.", "Manter os medicamentos inalatórios com formoterol/budesonida e associar salbutamol de alívio.", "Trocar os medicamentos para uma associação de terapia tripla inalatória (LAMA/LABA/corticoide) e associar oxigenoterapia domiciliar.", "Trocar os medicamentos inalatórios para uma associação LAMA/LABA e associar oxigenoterapia domiciliar."], correctIndex: 0 },
  { id: "unifesp_2026_041", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Homem, 70 anos de idade, é atendido no PS com quadro de cefaleia holocraniana em aperto, constante, de intensidade 3/10, que melhora pouco com analgésicos comuns, iniciado há cinco semanas. Além disso, acha que está mais lento e com dificuldade para falar. A esposa diz também que há 1 semana o paciente está mais apático. O exame neurológico mostra que o paciente está apático, respondendo às perguntas lentamente com monossílabos, com hemiparesia grau 4 em hemicorpo direito, com reflexos vivos e reflexo cutâneo-plantar em extensão à direita. Qual é o diagnóstico mais provável e o exame indicado para investigação?", options: ["Hematoma subdural esquerdo; tomografia de crânio.", "Meningioma parietal esquerdo; tomografia de crânio.", "Meningioma parietal direito; ressonância magnética de crânio.", "Hematoma cerebral à direita; ressonância magnética de crânio."], correctIndex: 0 },
  { id: "unifesp_2026_042", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 63 anos de idade, refere secura vaginal intensa, que piorou progressivamente nos últimos anos. O desconforto tem prejudicado sua vida sexual, e não teve melhora com o uso de lubrificantes. Realizou avaliação ginecológica recente sem alterações. Refere ter usado tibolona dos 50 aos 58 anos de idade. Qual é a conduta mais adequada?", options: ["laserterapia vulvar de baixa potência", "estrogenioterapia vaginal com estriol", "retornar a tibolona em baixa dose", "terapia estroprogestativa transdérmica"], correctIndex: 1 },
  { id: "unifesp_2026_043", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 34 anos de idade, IIG II Partos normais, refere estar em tratamento de transtorno bipolar há 2 anos, em uso de lamotrigina. Qual é o método contraceptivo mais adequado?", options: ["Medroxiprogesterona trimestral", "Etinilestradiol e desogestrel", "Estradiol e nomegestrol", "Diafragma"], correctIndex: 0 },
  { id: "unifesp_2026_044", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 34 anos de idade, nuligesta, com endometriose tratada clinicamente no passado, retorna com queixa de infertilidade há 18 meses. Ressonância magnética: endometriose profunda com nódulo em septo retovaginal e distorção anatômica. Ciclos ovulatórios regulares e parceiro com espermograma normal. Diante do desejo de engravidar, qual é a conduta mais adequada?", options: ["Indicar inseminação intrauterina diretamente, sem abordagem cirúrgica.", "Iniciar análogo de GnRH por 6 meses antes de liberar tentativas espontâneas.", "Realizar cirurgia conservadora para remoção das lesões profundas antes da tentativa de gestação.", "Contraindicar gestação espontânea e indicar preservação de óvulos para FIV."], correctIndex: 2 },
  { id: "unifesp_2026_045", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 72 anos de idade, refere ferida em vulva, prurido e sangramento há um ano. Foi medicada para dermatite de contato e micose, sem melhora. Exame físico: placa elevada, hiperemiada, 3 cm em terço médio de grande lábio esquerdo, próximo da prega genito-crural, com ulceração central e crostas hemáticas de 1 cm. Biópsia: carcinoma de células escamosas invasivo, associado a extensas áreas de neoplasia intraepitelial vulvar do tipo diferenciada. Estudo imunohistoquimíco: p16 negativo e p53 anormal. Qual é a conduta mais adequada?", options: ["Vulvectomia radical com linfadenectomia inguino-crural bilateral.", "Skinning vulvectomia.", "Quimioterapia e radioterapia.", "Hemivulvectomia esquerda com biópsia de linfonodo sentinela."], correctIndex: 3 },
  { id: "unifesp_2026_046", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Geriatria", text: "Mulher, 65 anos de idade, realizou exames que a ginecologista solicitou e preocupou-se ao ver o resultado da densitometria óssea cujo laudo apontou osteopenia em colo do fêmur. Ela passou a ter medo de quedas e fratura óssea. Qual é a orientação preventiva mais adequada em relação a medidas comportamentais para prevenção de queda?", options: ["Atividade física passiva e caminhar descalça com meia aderente.", "Exercícios resistidos e proprioceptivos e usar calçados apropriados.", "Exercícios sem impacto e utilizar órteses.", "Atividades física aquática e reorganizar o ambiente doméstico."], correctIndex: 1 },
  { id: "unifesp_2026_047", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Adolescente, 16 anos de idade, relata dismenorreia incapacitante com perda escolar recorrente desde a menarca aos 12 anos de idade. Já fez uso de vários antiinflamatórios não hormonais, analgésicos e anticoncepcional oral combinado cíclico por 6 meses, com pouca resposta. Nega início de vida sexual. Exame físico: abdome doloroso em hipogástrio. Ultrassonografia abdominal e pélvica sem alterações. Qual é a conduta mais adequada?", options: ["Iniciar progestagênio contínuo.", "Solicitar ressonância magnética abdominal.", "Indicar videolaparoscopia diagnóstica.", "Solicitar tomografia com contraste da pelve."], correctIndex: 0 },
  { id: "unifesp_2026_048", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 35 anos de idade, IIG II Partos cesáreas, refere perda urinária na corrida e urgência miccional ocasional, com piora progressiva há 6 meses. Exame físico: perda urinária em posição ortostática à manobra de Valsalva, Classificação POP-q: estádio IIA. Qual é a conduta mais adequada?", options: ["Prescrição de solifenacina", "Fisioterapia do assoalho pélvico", "Cirurgia de sling retropúbico", "Perineoplastia"], correctIndex: 1 },
  { id: "unifesp_2026_049", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 29 anos de idade, refere atraso menstrual há 6 semanas e sangramento genital em pequena quantidade há 1 dia. Exame físico: estável hemodinamicamente, abdome indolor e ao toque útero e anexos normais, colo impérvio. Realizou beta-hCG com valor de 750 mUI/ml e ultrassonografia transvaginal com eco endometrial de 8 mm e cisto com conteúdo anecóico em ovário direito medindo 30x20 mm com presença de halo vascular ao Doppler. Repetiu o beta-hCG em 48h com valor de 937 mUI/ml e a ultrassonografia inalterada. Qual é o diagnóstico mais provável?", options: ["Gravidez incipiente", "Gravidez inviável", "Tumor de sitio placentário", "Teratoma ovariano"], correctIndex: 1 },
  { id: "unifesp_2026_050", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Mulher, 40 anos de idade, no quarto período de um parto cefálico espontâneo, apresenta sangramento vaginal intenso. Diagnosticada com pré-eclampsia, está em uso de metildopa 2g/dia. Exame físico: PA 100 x 60 mmHg, FC 120bpm, útero 3cm acima da cicatriz umbilical e amolecido. Além da punção de 2 acessos calibrosos, infusão de cristaloides, qual é a conduta mais adequada?", options: ["Massagem uterina + ocitocina 10 UI intramuscular + misoprostol 800mcg via vaginal.", "Ácido tranexâmico 1g endovenoso + metilergometrina 0,2mg intramuscular.", "Ácido tranexâmico 1g + ocitocina 40 UI endovenosa + misoprostol 800mcg via retal.", "Tração controlada da placenta + ocitocina 10 UI intramuscular + acido tranexâmico 1g endovenoso."], correctIndex: 2 },
  { id: "unifesp_2026_051", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 32 anos de idade, não consegue engravidar há 3 anos. O casal tem relações sexuais frequentes (3-4 vezes por semana) sem métodos contraceptivos. O ciclo menstrual é regular. Nega dismenorreia. Exame físico: sem alterações. Qual é a conduta mais adequada?", options: ["Histerossalpingografia", "Dosagem de hormônios sexuais e tireoidianos", "Ultrassonografia transvaginal", "Teste de ovulação domiciliar"], correctIndex: 0 },
  { id: "unifesp_2026_052", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Primigesta, 33 anos de idade, teve parto normal há 30 dias, sem intercorrências. Comparece na consulta solicitando anticoncepção. Antecedentes Pessoais: heterozigose para o Fator V de Leyden e endometriose profunda. Não apresenta antecedentes de trombose venosa profunda. Qual é a conduta mais adequada?", options: ["Métodos de barreira", "Anticoncepcional hormonal combinado", "DIU de cobre", "DIU hormonal"], correctIndex: 3 },
  { id: "unifesp_2026_053", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Ginecologia", text: "Mulher, 66 anos de idade, sexualmente ativa, em novo relacionamento, encontra-se assintomática. Refere ter realizado anualmente exame citológico cérvico-vaginal preventivo sem alterações. De acordo com as Diretrizes Brasileiras atuais para o rastreamento para o câncer do colo uterino, qual é a conduta mais adequada?", options: ["Realizar exame citológico cérvico-vaginal a cada 3 anos.", "Realizar teste DNA-HPV oncogênico.", "Realizar exame citológico cérvico-vaginal anual.", "Não há necessidade de manter o rastreamento."], correctIndex: 1 },
  { id: "unifesp_2026_054", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Primigesta de 39 semanas, encontra-se em trabalho de parto. Ao toque vaginal, identifica-se a fontanela maior à esquerda, próxima à sínfise púbica, e a fontanela menor à direita e posterior. Qual é a variedade de posição fetal?", options: ["Occipito-posterior direita.", "Occipito-anterior esquerda.", "Occipito-transversa direita.", "Occípito-transversa esquerda."], correctIndex: 0 },
  { id: "unifesp_2026_055", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Parturiente, 20 anos de idade, primigesta, 33 semanas de idade gestacional, refere dor em baixo ventre e contrações há 5 horas, associada à cefaleia sem escotomas. Apresentou aumento da pressão arterial com 28 semanas, utilizando metildopa 500mg de 6 em 6 horas. Exame físico: PA 130 x 80mmHg, edema de membros inferiores 3+/4+, dinâmica uterina 3 contrações de 40 segundos em 10 minutos, apresentação cefálica e dorso a esquerda, cardiotocografia categoria I. Toque vaginal: colo com dilatação de 1 cm, grosso, posterior. Exames laboratoriais realizados há um dia: hemoglobina 11,2g/dL, Plaquetas 130.000 plaquetas/mm3, TGO 75 UI/L, Urina tipo 1 com proteinúria 2+/4+. Qual é a conduta mais adequada?", options: ["Parto cesáreo e sulfato de magnésio.", "Assistência do trabalho de parto e sulfato de magnésio.", "Inibição do trabalho de parto com nifedipino e betametasona.", "Inibição do trabalho de parto com sulfato de magnésio e betametasona."], correctIndex: 1 },
  { id: "unifesp_2026_056", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Parturiente com idade gestacional de 37 semanas internou com perda de líquido amniótico há 5 horas. Pré-natal sem intercorrências, salvo por infecção urinária por Streptococcus B, tratada no segundo trimestre. A cultura vaginal e do intróito anal para Streptococcus B com 35 semanas foi negativa. Exame Físico: AU: 34 cm, DU 3/50\"/10 min, BCF 148 bpm, colo médio, medianizado 4 cm, apresentação cefálica. Qual é a conduta mais adequada?", options: ["Evitar o toque vaginal, ausculta intermitente e evolução do trabalho de parto.", "Penicilina G cristalina 5 milhões de UI + 2,5 milhões de UI de 4 em 4 horas.", "Ampicilina 4 gramas seguida de 2 gramas a cada 4 horas.", "Cefazolina 2 gramas após 18 horas de rotura das membranas."], correctIndex: 1 },
  { id: "unifesp_2026_057", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Primigesta, 38 anos de idade, 37 semanas, com diagnóstico de diabetes gestacional insulino dependente. Na última semana demonstra maior número de episódios de hipoglicemia com a mesma dose de insulina. Exame físico: AU 37 cm, dinâmica uterina ausente, colo grosso, posterior e impérvio. Ultrassonografia: circunferência abdominal no percentil 95, maior bolsão de líquido amniótico 9,0 cm e Dopplervelocimetria dentro dos padrões da normalidade. Qual é a conduta mais adequada?", options: ["Parto cesáreo imediato.", "Controle de vitalidade por cardiotocografia e parto com 39 semanas.", "Indução de parto imediato.", "Controle de vitalidade do perfil biofísico fetal e parto com 39 semanas."], correctIndex: 2 },
  { id: "unifesp_2026_058", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Gestante, 25 anos de idade, com 12 semanas de gravidez, comparece à consulta de pré-natal sem queixas. Refere parceiro fixo há 5 anos, saudável, atualmente em privação de liberdade, que não aceita uso de preservativo. Antecedentes pessoais: sífilis tratada com comprovação de tratamento e seguimento há 1 ano. Exames subsidiários: Teste rápido de HIV negativo. Qual é a conduta mais adequada?", options: ["Prescrever profilaxia pré-exposição (PrEP) sob demanda, antes e após relação sexual.", "Prescrever profilaxia pós-exposição (PEP).", "Prescrever terapia antiretroviral (TARV).", "Prescrever profilaxia pré-exposição (PrEP) de uso contínuo."], correctIndex: 3 },
  { id: "unifesp_2026_059", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Obstetrícia", text: "Primigesta, 36 anos de idade, com 13 semanas de gestação, comparece para realização de ultrassonografia morfológica de primeiro trimestre. Foi identificado defeito aberto da parede abdominal compatível com onfalocele. A medida da transluscência nucal foi de 2,0 mm, com osso nasal presente. Qual é a conduta mais adequada?", options: ["Amniocentese", "Biópsia de vilo corial", "Microarray não invasivo", "Teste pré-natal não invasivo"], correctIndex: 1 },
  { id: "unifesp_2026_060", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Radiologia", text: "Homem, 44 anos de idade, com dor abdominal aguda, realiza ultrassonografia abdominal com imagem hiperecogênica na luz da vesícula biliar e sombra acústica posterior. Sobre os achados de imagem, assinale a alternativa correta.", options: ["As setas indicam um cálculo na vesícula biliar, o qual se apresenta como imagem hiperecogênica com sombra acústica posterior.", "As setas indicam um pólipo na vesícula biliar, o qual se apresenta como imagem hiperecogênica com sombra acústica posterior.", "As setas indicam um cálculo na vesícula biliar, o qual se apresenta como imagem hipoecogenica com reforço acústico posterior.", "As setas indicam um pólipo na vesícula biliar, o qual se apresenta como imagem hipoecogênica com reforço acústico posterior."], correctIndex: 0 },
  { id: "unifesp_2026_061", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Radiologia", text: "Homem, 30 anos de idade, com lombalgia, disponibiliza na consulta imagens de ressonância magnética de coluna lombar demonstrando alteração de sinal discal e fragmento discal extruso comprimindo o saco tecal. Assinale a alternativa correta.", options: ["Trata-se de uma ressonância magnética com diagnóstico de espondilite anquilosante.", "Trata-se de uma tomografia computadorizada com diagnóstico de doença degenerativa discal e de hérnia discal extrusa.", "Trata-se de uma ressonância magnética com diagnóstico de doença degenerativa discal e de hérnia discal extrusa.", "Trata-se de uma tomografia computadorizada com diagnóstico de espondilodiscite infecciosa."], correctIndex: 2 },
  { id: "unifesp_2026_062", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Genética", text: "Homem, 35 anos de idade, em tratamento para câncer colorretal, relata que sua mãe faleceu aos 40 anos devido a câncer de endométrio e que seu avô materno teve câncer do trato urotelial aos 50 anos. O quadro clínico e história familiar sugerem:", options: ["herança autossômica recessiva e variante germinativa em homozigose em genes de predisposição a câncer.", "herança ligada ao X com possível envolvimento de variante somática em gene de predisposição a câncer.", "herança autossômica dominante e variante germinativa em heterozigose em genes de predisposição a câncer.", "herança multifatorial com variante germinativa em heterozigose composta em genes de predisposição a câncer"], correctIndex: 2 },
  { id: "unifesp_2026_063", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Um estudo de coorte detectou incidência de 24% da doença D entre expostos a um fator de risco. Sabendo que o exame diagnóstico para detectar essa incidência tinha sensibilidade de 100% e especificidade de 80%, qual teria sido a verdadeira incidência de D nessa coorte?", options: ["5,0%", "19,2%", "24,0%", "31,6%"], correctIndex: 0 },
  { id: "unifesp_2026_064", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Psiquiatria", text: "Homem, 52 anos de idade, etilista crônico (1 litro de cachaça/dia há 20 anos), é internado e tratado por quadro de pneumonia. Após 48 horas de internação, apresenta agitação psicomotora intensa, sudorese profusa, tremores grosseiros de extremidades, FC = 130 bpm, PA = 170/100 mmHg, alucinações visuais de insetos e desorientação no tempo e espaço. Qual o tratamento farmacológico inicial de escolha para esse paciente?", options: ["Haloperidol", "Diazepam", "Clozapina", "Risperidona"], correctIndex: 1 },
  { id: "unifesp_2026_065", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Psiquiatria", text: "Mulher, 28 anos de idade, é atendida após episódio de uma semana de euforia, autoestima grandiosa, fala acelerada, redução da necessidade de sono, aumento da energia, ideias de investimento sem critério e comportamento de risco. O quadro levou a conflitos familiares e necessidade de afastamento do trabalho. Há dois anos, apresentou episódio depressivo de longa duração, com tristeza intensa, anedonia e insônia. Qual o diagnóstico mais provável?", options: ["Transtorno depressivo recorrente", "Transtorno ciclotímico", "Transtorno bipolar tipo II", "Transtorno bipolar tipo I"], correctIndex: 3 },
  { id: "unifesp_2026_066", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Você trabalha em um Núcleo Hospitalar de Epidemiologia. Assim que chega ao local de trabalho, você é informado sobre os casos a seguir que deram entrada no hospital nas últimas 12 horas. Assinale a alternativa que contém o caso a ser imediatamente notificado à Secretaria Municipal de Saúde.", options: ["Homem, 29 anos, cozinheiro, que teve o dedo amputado durante a jornada de trabalho.", "Mulher, 40 anos, servidora pública, com teste de dengue NS1 positivo, sem história de viagem nos últimos 15 dias.", "Adolescente, sexo masculino, 15 anos de idade, institucionalizado, com Elisa-IgM reagente para Zika.", "Criança, 8 anos de idade, atendida por suspeita de hepatite A."], correctIndex: 0 },
  { id: "unifesp_2026_067", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Legal", text: "Mulher, 28 anos de idade, comparece a um serviço de atenção primária à saúde solicitando teste de gravidez, afirmando que precisa do resultado para ser contratada em uma vaga de emprego. Ela relata que a empresa exigiu o exame como parte do processo admissional. Como o médico deve proceder diante dessa solicitação?", options: ["Realizar o exame se a paciente trouxer a solicitação da empresa por escrito.", "Recusar a solicitação, devendo orientar a paciente sobre seus direitos.", "Realizar o exame se a paciente assinar o termo de consentimento.", "Solicitar autorização prévia ao Conselho Regional de Medicina para realizar o exame."], correctIndex: 1 },
  { id: "unifesp_2026_068", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em 1854 o médico inglês John Snow investigava se havia associação entre a água fornecida por duas companhias de abastecimento público e a epidemia de cólera em Londres. Suas palavras: \"Os canos das duas companhias percorrem todas as ruas, entrando em praticamente todos os becos. Algumas casas são abastecidas por uma companhia e algumas pela outra (...). Em muitos casos, o abastecimento de uma casa é diferente das duas outras que lhe são vizinhas. Ambas as companhias abastecem tanto casas ricas como pobres, grandes ou pequenas; não há nenhuma diferença, nem na condição social, nem na ocupação das pessoas que delas recebem a água.\". Em termos epidemiológicos atuais pode-se dizer que a situação descrita por Snow se assemelha às condições obtidas em um estudo:", options: ["caso-controle.", "transversal.", "experimental.", "ecológico."], correctIndex: 2 },
  { id: "unifesp_2026_069", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Um estudo prospectivo analisou a obesidade, a dieta e os hábitos de exercício físico de indivíduos de uma universidade. Qual é o teste adequado para avaliar se o índice de massa corpórea médio é o mesmo para o consumo baixo e alto de gordura?", options: ["Análise de correlação", "Teste Qui-quadrado", "Teste t de Student", "Análise de variância (ANOVA)"], correctIndex: 2 },
  { id: "unifesp_2026_070", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Mulher, 56 anos de idade, atendida em uma Unidade Básica de Saúde, apresenta nódulo mamário e gânglio ipsilateral axilar palpáveis. O médico a encaminha para mamografia e o Setor de Regulação Municipal já tem fila de espera com 250 pacientes. Essa usuária é classificada como prioridade e, com base no Protocolo de Acesso, tem seu exame agendado em cinco dias. Qual o princípio doutrinário do SUS que garante a priorização desse agendamento?", options: ["Equidade", "Integralidade", "Hierarquização", "Resolubilidade"], correctIndex: 0 },
  { id: "unifesp_2026_071", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Legal", text: "Menina, 13 anos de idade, procura atendimento em uma UBS, acompanhada de sua mãe. Relata estar com 23 semanas de gestação, decorrente de relação sexual consensual com seu namorado de 15 anos de idade. Mãe e filha expressam o desejo de interromper a gestação. Com base na legislação brasileira vigente, a interrupção da gestação:", options: ["não está autorizada, pois não houve violência física e nem coação.", "é permitida independentemente da idade gestacional.", "dependerá de comprovação legal do estupro por meio de laudo pericial.", "não está autorizada, por ultrapassar 22 semanas de gestação."], correctIndex: 1 },
  { id: "unifesp_2026_072", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Legal", text: "Em 16 de abril de 2025, a Agência Nacional de Vigilância Sanitária (Anvisa) estabeleceu medidas mais rigorosas para a prescrição e dispensação dos medicamentos agonistas do receptor de Glucagon-Like Peptide-1 (GLP-1) (como semaglutida e liraglutida, entre outros), a partir da retenção da receita. Essa decisão foi motivada, principalmente, pelo aumento significativo de eventos adversos associados ao uso desses fármacos fora das indicações aprovadas pela Agência. Conforme decisão, esta classe de medicamentos deverá ser prescrita em:", options: ["receituário branco, especial, em duas vias.", "receituário Azul (B).", "receituário Amarelo (A).", "receituário branco, especial, em uma via."], correctIndex: 0 },
  { id: "unifesp_2026_073", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Medicina Legal", text: "Durante a assistência a uma parturiente de 29 anos, G2P1, cardiotocografia categoria I, a equipe obstétrica indica a episiotomia. A paciente recusa o procedimento após ser orientada sobre seus riscos e benefícios. A recusa é registrada no prontuário. No parto ocorre uma laceração perineal de terceiro grau, com extensão até o esfincter anal. Após o parto, familiares questionam a conduta da equipe, alegando que a lesão poderia ter sido evitada com a episiotomia. Com base nos princípios da bioética e na legislação brasileira vigente, assinale a alternativa correta.", options: ["A episiotomia, por ser um procedimento de urgência obstétrica, não depende de consentimento da gestante e sua recusa não deve ser acatada.", "A recusa de intervenções padronizadas como a episiotomia deve ser formalizada em plano de parto escrito; na ausência desse documento, prevalece a decisão da equipe.", "A conduta da equipe foi ética e legalmente adequada, pois respeitou a autonomia da gestante, prestou esclarecimentos prévios e registrou a recusa.", "A equipe médica poderá ser responsabilizada por negligência, já que a recusa do procedimento não isenta o profissional do dever de agir para prevenir lesões maternas."], correctIndex: 2 },
  { id: "unifesp_2026_074", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "O quadro abaixo resume os resultados de um estudo epidemiológico sobre fratura de fêmur, considerando sexo e idade: risco relativo mulheres/homens de todas as idades = 2,0; em idade < 50 anos, RR = 0,5; em idade ≥ 50 anos, RR = 8,0. Em relação à associação entre sexo e fratura de fêmur, a idade, com base nesses dados, é considerada uma variável:", options: ["modificadora de efeito.", "de confusão.", "indutora de viés de aferição.", "de indução estatística"], correctIndex: 0 },
  { id: "unifesp_2026_075", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em um estudo de pesquisa, a idade dos participantes era de 26 anos ± 5 anos (média ± desvio padrão). Qual das afirmações a seguir é a correta?", options: ["É 95% certo de que a média verdadeira está dentro do intervalo de 16 a 36 anos.", "A maioria dos participantes tinha 26 anos; os restantes tinham entre 21 e 31 anos.", "Nenhum participante tinha menos de 16 anos ou mais de 36 anos.", "Aproximadamente, 95% dos participantes tinham entre 16 e 36 anos."], correctIndex: 3 },
  { id: "unifesp_2026_076", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em um estudo de coorte metade das pessoas são expostas a um fator de risco (FR). Nesses expostos, o risco de morrer em 10 anos foi 10%, enquanto nos não expostos foi 5%. Havendo causalidade na associação entre exposição ao FR e morte, que proporção do total de mortes poderia ser evitada se o FR fosse eliminado nessas pessoas?", options: ["1/2", "1/3", "1/4", "1/5"], correctIndex: 1 },
  { id: "unifesp_2026_077", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "O Planejamento Regional Integrado (PRI) é instrumento estratégico e obrigatório para a organização das Redes de Atenção à Saúde nas regiões de saúde do Brasil. Qual referencial embasa a elaboração e pactuação do PRI a ser realizada pelos entes federados do âmbito municipal, estadual e federal?", options: ["Capacidade instalada de serviços de saúde.", "Necessidades de saúde da população.", "Emendas parlamentares federais.", "Acesso da população à atenção especializada."], correctIndex: 1 },
  { id: "unifesp_2026_078", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Qual dos objetivos abaixo é o mais provável de ser atingido com um estudo epidemiológico do tipo caso controle?", options: ["Estimar a frequência de doenças raras na população.", "Avaliar a eficácia de programas de rastreamento populacional.", "Estimar a frequência de doenças crônicas na população.", "Avaliar a efetividade de uma vacina."], correctIndex: 3 },
  { id: "unifesp_2026_079", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em um estudo do tipo caso-controle, qual é a vantagem de se utilizarem casos prevalentes ao invés de casos incidentes?", options: ["Selecionar muitos casos em pouco tempo.", "Estimar a prevalência da doença estudada.", "Minimizar a ocorrência de viés de recordação.", "Estimar a incidência da doença estudada."], correctIndex: 0 },
  { id: "unifesp_2026_080", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Cinquenta e três indivíduos sedentários participaram de um estudo para avaliar a capacidade física através de um teste de corrida. A pressão diastólica (mmHg) foi medida em cada indivíduo antes e ao final da corrida. O intervalo de 95% de confiança para a mudança média da pressão diastólica (final-inicial) resultante foi de [0,82; 5,59]. Com base nesses resultados assinale a alternativa correta.", options: ["Ao nível de significância de 95%, não há diferença estatisticamente significante entre 0,82 e 5,59 mmHg.", "Noventa e cinco por cento dos indivíduos têm mudança na pressão diastólica entre 0,82 e 5,59 mmHg nos momentos avaliados.", "Há indícios de diferença estatisticamente significativa entre as médias da pressão diastólica quando comparamos os momentos avaliados ao nível de significância de 5%.", "Como o intervalo de 95% de confiança engloba o valor unitário, pode-se afirmar que não houve diferença de pressão diastólica nos momentos avaliados."], correctIndex: 2 },
  { id: "unifesp_2026_081", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "A discussão acerca do sobrediagnóstico (overdiagnosis) vem sendo cada vez mais abordada nas publicações clínico-epidemiológicas atuais. Isso ocorre, entre outros motivos, porque:", options: ["exames diagnósticos com resultados falsos positivos vêm causando um excesso de intervenções.", "a especificidade dos testes diagnósticos preventivos vem aumentando consistentemente.", "a prevenção quaternária vem se impondo ante o excesso de intervenções médicas desnecessárias.", "a prevenção secundária vem sendo pouco privilegiada nas políticas de saúde pública."], correctIndex: 2 },
  { id: "unifesp_2026_082", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Estima-se que o R0 (Basic Reproductive Number) de uma doença respiratória emergente, cuja transmissão se dá por meio de gotículas, é igual a 4. Há uma vacina contra essa doença, capaz de induzir soroconversão em 100% dos vacinados. Para que não ocorra uma epidemia, que porcentagem mínima da população deverá ser vacinada?", options: ["95% da população.", "60% da população.", "90% da população.", "75% da população."], correctIndex: 3 },
  { id: "unifesp_2026_083", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente de 32 dias de vida é trazido à consulta no pediatra após recoleta do teste do pezinho para fibrose cística. O primeiro resultado do tripsinogênio imunorreativo (IRT), com 3 dias de vida, foi alterado e o segundo, com 20 dias de vida, foi normal. Qual é a orientação correta para esta família?", options: ["Fazer acompanhamento pediátrico de rotina.", "Prosseguir investigação com dosagem de cloro no suor.", "Prosseguir investigação com sequenciamento do gene CRTF.", "Dosar IRT em nova amostra após 30 dias de vida."], correctIndex: 0 },
  { id: "unifesp_2026_084", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido filho de mãe vivendo com HIV, considerado de alto risco para infecção vertical, recebe profilaxia ao nascimento com 3 drogas antirretrovirais. Aos 14 dias de vida, apresenta carga viral de 80 cópias/mL em teste de PCR quantitativo. Qual é a conduta mais adequada diante desse resultado?", options: ["Suspender o tratamento preemptivo e iniciar tratamento antirretroviral definitivo.", "Coletar imediatamente um DNA pró-viral ou uma nova carga viral para confirmação diagnóstica.", "Solicitar carga viral novamente em 30 dias e repetir em 2 semanas se o novo resultado for indetectável.", "Considerar o recém-nascido infectado e orientar o tratamento segundo a genotipagem."], correctIndex: 1 },
  { id: "unifesp_2026_085", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino nasceu com idade gestacional de 33 semanas, de parto cesáreo por indicação materna (placenta prévia com sangramento) e evoluiu com desconforto respiratório desde o nascimento. No segundo dia de vida, apresentou pausa respiratória de 15 segundos acompanhada de FC = 80 bpm. Exame físico: mantém taquipneia sem outras alterações. RX de tórax com infiltrado intersticial bilateral com aumento de área cardíaca e hemograma com escore hematológico de Rodwell = 2. Qual droga pode beneficiar este recém-nascido?", options: ["Furosemida.", "Ampicilina.", "Surfactante.", "Cafeína."], correctIndex: 3 },
  { id: "unifesp_2026_086", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina, 13 anos de idade, apresenta queixa de lesões em face que pioram com o sol, além de dor e edema nas articulações de punhos e alguns dedos há 3 meses. Refere febre esporádica. Apresenta alteração de urina, que está escura e com espuma. Qual é a alteração mais provável de ser encontrada no exame de urina?", options: ["Hematúria com dismorfismo eritrocitário.", "Leucocitúria sem cilindrúria.", "Relação proteinúria/creatinúria <0,2.", "Alteração de pH e cilindros hialinos."], correctIndex: 0 },
  { id: "unifesp_2026_087", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 1 ano e 8 meses de idade, nascido a termo com peso de 2.720 gramas, sem intercorrências desde o nascimento. Recebeu aleitamento materno exclusivo até 6 meses e atualmente come todos os grupos alimentares em pequena quantidade, pois prefere o seio materno. Exame físico: descorado, sem outras alterações. Hemograma: Hb = 8,2 g/dL, Ht = 23%, microcitose, leucócitos = 17.000/mm³, plaquetas = 970.000/mm³ e bioquímica do ferro normal. Considerando o diagnóstico mais provável, qual o exame a ser solicitado para confirmação?", options: ["Dosagem de G6PD.", "Mielograma.", "Eletroforese de hemoglobina.", "Curva de fragilidade osmótica."], correctIndex: 2 },
  { id: "unifesp_2026_088", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina, 3 anos de idade, hígida, há 2 dias apresenta evacuações líquidas com raias de sangue, sem febre ou dor abdominal. Exame físico sem alterações. Considerando o diagnóstico, além de manter a alimentação habitual e aumentar a oferta de líquidos ou soro de reidratação oral após cada evacuação diarreica, qual é a orientação adicional recomendada pelo Ministério da Saúde?", options: ["Orientar sinais de alarme para retorno e solicitar coprocultura.", "Prescrever azitromicina com retorno em 2 dias.", "Prescrever probiótico com retorno em 2 dias.", "Prescrever zinco e orientar sinais de alarme para retorno."], correctIndex: 3 },
  { id: "unifesp_2026_089", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 6 meses de idade, sem comorbidades, inicia com coriza e obstrução nasal, evoluindo após 2 dias com tosse e desconforto respiratório. Exame físico: bom estado geral, sibilos expiratórios, tempo expiratório prolongado, retração subcostal e de fúrcula com SpO2 = 93%. Exame complementar: teste rápido positivo para vírus sincicial respiratório. Qual das seguintes intervenções é recomendada pela Sociedade Brasileira de Pediatria?", options: ["Inalação salina hipertônica a 3%.", "Broncodilatador inalatório.", "Corticoide por via oral.", "Oxigenoterapia inalatória."], correctIndex: 0 },
  { id: "unifesp_2026_090", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido, 34 semanas de idade gestacional, nascido de parto cesáreo de urgência por pré-eclâmpsia materna, necessitou de ventilação com pressão positiva na sala de parto. Apresentou sinais de desconforto respiratório com 5 minutos de vida. Assinale a alternativa que apresenta a hipótese diagnóstica mais provável e sua respectiva fisiopatologia.", options: ["Hipertensão pulmonar persistente neonatal pela hipoalveolização pulmonar.", "Síndrome do desconforto respiratório do recém-nascido por retardo na reabsorção do líquido pulmonar.", "Taquipneia transitória do recém-nascido por aumento da produção do líquido pulmonar.", "Síndrome de escape de ar por rompimento da bainha broncoalveolar."], correctIndex: 3 },
  { id: "unifesp_2026_091", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 5 anos de idade, apresenta febre de até 39,2°C há 72 horas, de difícil controle com antitérmicos, sem sintomas respiratórios ou gastrointestinais, além de diminuição da aceitação alimentar e irritabilidade. Exame físico: não postectomizado. Exames laboratoriais: urina tipo 1: pH = 7, densidade = 1015, leucócitos = 380.000/mL, hemácias = 10.000/mL, nitrito e bactérias positivos; hemograma com neutrofilia e desvio à esquerda, hemoglobina e plaquetas normais. Ultrassonografia de rins e vias urinárias com presença de cálculo coraliforme ocupando a pelve renal direita. Qual é o agente etiológico mais provável para este paciente?", options: ["Klebsiella pneumoniae.", "Escherichia coli.", "Staphylococcus saprophyticus.", "Proteus mirabilis."], correctIndex: 3 },
  { id: "unifesp_2026_092", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 8 anos de idade, estudante do 3º ano do ensino fundamental, apresenta dificuldades persistentes para acompanhar as atividades de leitura em sala de aula. Apesar de ter inteligência preservada e bom desenvolvimento em outras áreas, lê de forma lenta, com muitos erros de decodificação e troca frequente de letras com sons parecidos (ex.: \"p/b\", \"f/v\"). Sua escrita apresenta omissões e inversões de letras. O professor relata que compreende bem os conteúdos quando escutados, expressa-se bem oralmente, mas tem pouca atenção na sala de aula e baixo desempenho em provas escritas. Seus pais possuem o ensino fundamental I. Qual é a hipótese diagnóstica mais provável?", options: ["Transtorno específico da aprendizagem.", "Transtorno de déficit de atenção/hiperatividade.", "Transtorno do espectro autista.", "Transtorno do desenvolvimento da linguagem."], correctIndex: 0 },
  { id: "unifesp_2026_093", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina, 7 anos de idade, apresenta sono agitado com ronco frequente e sudorese profusa. Considerando o diagnóstico mais provável, qual é a comorbidade mais frequentemente associada a este quadro?", options: ["Fibrilação atrial.", "Hipertensão arterial.", "Alteração comportamental.", "Obesidade."], correctIndex: 2 },
  { id: "unifesp_2026_094", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina, 9 anos de idade, em tratamento para leucemia linfoide aguda, apresenta recidiva precoce, sem opções curativas disponíveis. Os pais, bastante angustiados, solicitam uma reunião com a equipe de saúde. O médico responsável convida a psicóloga e a enfermeira para participar do encontro. Durante a conversa, o pai insiste que \"a filha não pode saber da gravidade\", enquanto a mãe se mostra em dúvida, dizendo que a menina já percebe que algo está acontecendo. A criança, por sua vez, vem fazendo perguntas diretas à equipe sobre seu tratamento e alta hospitalar. Após o reconhecimento dos sentimentos dos pais, qual deve ser a conduta mais adequada da equipe ao comunicar más notícias neste contexto?", options: ["Atender ao pedido do pai e conversar com a criança minimizando a gravidade do quadro, preservando-a do sofrimento.", "Fornecer informações à criança de acordo com seu nível de compreensão, garantindo sua autonomia no processo de decisão.", "Priorizar a comunicação realizada pela equipe multiprofissional, a fim de minimizar o impacto emocional.", "Avaliar o grau de compreensão e desejo de informação da criança, e construir junto à família uma forma adequada de comunicação."], correctIndex: 3 },
  { id: "unifesp_2026_095", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 4 anos de idade, apresenta cansaço há 1 dia e tosse seca com piora há 3 horas. Paciente tem asma e parou a medicação de controle há 1 semana por estar sem crise há 2 meses. Exame físico: FR = 42 irpm, fala apenas frases curtas, SpO2 = 95% em ar ambiente. De acordo com o GINA (Global Initiative for Asthma), qual é a classificação da crise e a conduta imediata?", options: ["Crise grave; beta-2 agonista de curta ação associado a brometo de ipratrópio.", "Crise moderada; beta-2 agonista de curta ação associado a brometo de ipratrópio.", "Crise moderada; indicação de beta-2 agonista de longa ação.", "Crise grave; indicação de beta-2 agonista de longa ação."], correctIndex: 0 },
  { id: "unifesp_2026_096", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina, 5 anos de idade, transplantada renal há 2 anos, faz uso contínuo de imunossupressores. Durante a consulta, a família questiona sobre vacinação contra a COVID-19. Qual deve ser a orientação para a família?", options: ["A vacinação contra a COVID-19 é indicada apenas para os contactantes domiciliares.", "A vacinação contra a COVID-19 é indicada se os imunossupressores forem temporariamente suspensos.", "A vacinação contra a COVID-19 é indicada no esquema habitual.", "A vacinação contra a COVID-19 é indicada com doses adicionais."], correctIndex: 3 },
  { id: "unifesp_2026_097", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 3 anos de idade, sabidamente alérgico ao leite de vaca, apresenta vômitos recorrentes, urticária e tosse após ingestão acidental de leite. Recebe adrenalina intramuscular no serviço de emergência, evoluindo satisfatoriamente, com regressão total dos sintomas. Qual é a conduta mais adequada nesse momento?", options: ["Prescrever anti-histamínico intramuscular e indicar internação hospitalar.", "Prescrever corticoide endovenoso e solicitar IgE específica para leite de vaca.", "Manter observação clínica por 6 horas e prescrever corticoide oral.", "Alta do serviço com prescrição de anti-histamínico oral."], correctIndex: 2 },
  { id: "unifesp_2026_098", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido de 20 dias, nascido a termo, parto vaginal, sem intercorrências perinatais, é levado ao PS com febre há 6 horas (temperatura axilar de 38,3°C) e recusa das mamadas. Exame físico: irritado, T = 38,5°C, FC = 168 bpm, tempo de enchimento capilar = 2 segundos, sem outras alterações. Além de hemograma, PCR e hemocultura, que exames devem ser solicitados na investigação inicial?", options: ["PCR para vírus respiratórios e RX de tórax.", "Urina tipo 1 e urocultura em saco coletor.", "Líquor e RX de tórax.", "Líquor, urina tipo 1 e urocultura por sondagem vesical."], correctIndex: 3 },
  { id: "unifesp_2026_099", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 9 anos de idade, apresenta dor abdominal, distensão, diarreia sem sangue e flatulência que se inicia após a ingestão de leite de vaca integral. Não apresenta sintomas quando ingere iogurte. O quadro se iniciou há cerca de 2 anos. Exame físico: normal. Qual é a principal hipótese diagnóstica?", options: ["Intolerância à lactose congênita.", "Intolerância à lactose secundária.", "Hipolactasia do tipo adulto.", "Alergia à lactose."], correctIndex: 2 },
  { id: "unifesp_2026_100", banca: "UNIFESP", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina, 11 anos de idade, chega ao PS com dor abdominal progressiva há 3 semanas. Exame físico: bom estado geral, com tumor de consistência endurecida, palpável na região do hipogástrio. Ultrassom da região pélvica: tumor sólido no ovário esquerdo. Qual é o marcador laboratorial que se espera encontrar positivo na investigação desta adolescente?", options: ["Beta HCG.", "Ferritina.", "Alfa-fetoproteína.", "Ácido vanilmandélico."], correctIndex: 0 },
];
